import sys

def shortest_palindrome(s):
    if not s:
        return ""

    n = len(s)
    lps = [0] * n  # Longest Proper Prefix which is also a Suffix

    length = 0  # Length of the previous longest prefix suffix

    for i in range(1, n):
        while length > 0 and s[i] != s[length]:
            length = lps[length - 1]

        if s[i] == s[length]:
            length += 1
            lps[i] = length

        # If the entire string is a palindrome, break early
        if lps[i] == n:
            break

    # The minimum number of characters to add is (n - lps[n-1])
    # Add the reverse of the substring from 0 to (n - lps[n-1] - 1)
    return s + s[:n - lps[n-1] - 1][::-1]

def main():
    s = sys.stdin.readline().strip()
    print(shortest_palindrome(s))

if __name__ == "__main__":
    main()
